#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>

#include "common.h"

static int do_verify = 0;

static struct option long_options[] = {
  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

extern void
lud_cuda(float *m, int matrix_dim);

int
main ( int argc, char *argv[] )
{
  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  }
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }

  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  } 

  if (do_verify){
    printf("Before LUD\n");

    matrix_duplicate(m, &mm, matrix_dim);
  }


  stopwatch_start(&sw);
  lud_cuda(m, matrix_dim);
  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");

    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}				

// CUDA Implementation of LUD
#define BS 16

__global__ void lud_diagonal_cuda(float* a, int size, int offset)
{
    int i, j, k;
    for (i = 0; i < BS; i++) {
        for (j = i; j < BS; j++) {
            float sum = 0.0f;
            for (k = 0; k < i ; k++) {
                sum += a[(offset+i)*size+(offset+k)] * a[(offset+k)*size+(offset+j)];
            }
            a[(offset+i)*size+(offset+j)] -= sum;
        }

        float temp = 1.f/a[(offset+i)*size+(offset+i)];
        for (j = i+1; j < BS; j++) {
            float sum = 0.0f;
            for (k = 0; k < i ; k++) {
                sum += a[(offset+j)*size+(offset+k)] * a[(offset+k)*size+(offset+i)];
            }
            a[(offset+j)*size+(offset+i)] = (a[(offset+j)*size+(offset+i)] - sum) * temp;
        }
    }
}

__global__ void lud_inter_row_cuda(float* a, int size, int offset, int chunks_in_inter_row)
{
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k, i_global, j_global, i_here, j_here;
    float sum;           
    float temp[BS*BS];

    int row_offset = offset;
    int col_offset = offset;

    // Load temp block (top)
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp[i*BS + j] = a[size*(i + row_offset) + col_offset + j ];
        }
    }

    i_global = row_offset;
    j_global = col_offset + BS * (chunk_idx+1);

    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            sum = 0.f;
            for (k=0; k < i; k++) {
                sum += temp[BS*i +k] * a[(i_global+k)*size+(j_global+j)];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            a[i_here*size + j_here] -= sum;
        }
    }

    j_global = col_offset;
    i_global = row_offset + BS * (chunk_idx + 1);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum = 0.f;
            for (k=0; k < j; k++) {
                sum += a[(i_global+i)*size+(j_global+k)] * temp[BS*k + j];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            float divisor = a[size*(offset+j) + offset+j];
            a[size*i_here + j_here] = ( a[size*i_here+j_here] - sum ) / divisor;
        }
    }
}

__global__ void lud_inter_block_cuda(float* a, int size, int offset, int chunks_in_inter_row, int chunks_per_inter)
{
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_per_inter) return;

    int i, j, k, i_global, j_global;
    float temp_top[BS*BS];
    float temp_left[BS*BS];
    float sum[BS];

    i_global = offset + BS * (1 +  chunk_idx/chunks_in_inter_row);
    j_global = offset + BS * (1 + chunk_idx%chunks_in_inter_row);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp_top[i*BS + j]  = a[size*(i + offset) + j + j_global ];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    for (i = 0; i < BS; i++)
    {
        for (j = 0; j < BS; j++) sum[j] = 0.f;

        for (k=0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }

        for (j = 0; j < BS; j++) {
            a[(i+i_global)*size+(j+j_global)] -= sum[j];
        }
    }
}

void lud_cuda(float *a, int size)
{
    int offset, chunk_idx, size_inter, chunks_in_inter_row, chunks_per_inter;

    float *d_a;
    cudaMalloc(&d_a, size*size*sizeof(float));
    cudaMemcpy(d_a, a, size*size*sizeof(float), cudaMemcpyHostToDevice);

    int bs = BS;

    for (offset = 0; offset < size - bs; offset += bs)
    {
        // Diagonal block
        lud_diagonal_cuda<<<1, 1>>>(d_a, size, offset);

        size_inter = size - offset - bs;
        chunks_in_inter_row  = size_inter/bs;

        if (chunks_in_inter_row > 0) {
            // Inter-row updates
            int threads = 256;
            int blocks = (chunks_in_inter_row + threads - 1) / threads;
            lud_inter_row_cuda<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row);

            // Inter-block updates
            chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
            blocks = (chunks_per_inter + threads - 1) / threads;
            lud_inter_block_cuda<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row, chunks_per_inter);
        }
    }

    // Final diagonal block
    lud_diagonal_cuda<<<1, 1>>>(d_a, size, offset);

    cudaMemcpy(a, d_a, size*size*sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_a);
}
